   359→  }
   360→}
   361→
   362→/**
   363→ * Calculate enhanced scores by applying AI feature confidence boosts
   364→ */
   365→function calculateEnhancedScores(
   366→  candidateCategories: Record<string, number>,
   367→  extractedFeatures: FeatureExtractionData,
   368→  enhancementCalculations: EnhancementCalculation[],
   369→  validationErrors: string[]
   370→): Record<string, number> {
   371→  const enhancedScores: Record<string, number> = {};
   372→
   373→  // Validate extracted features format
   374→  if (!extractedFeatures.semanticIntent || !extractedFeatures.categoryEnhancements) {
   375→    validationErrors.push('Invalid extracted features format');
   376→    // Fallback to original scores without enhancement
   377→    return { ...candidateCategories };
   378→  }
   379→
   380→  for (const [category, originalScore] of Object.entries(candidateCategories)) {
   381→    let enhancedScore = originalScore;
   382→    let confidenceBoost = 0;
   383→    let boostReason = 'No feature enhancement';
   384→
   385→    // Apply AI feature enhancement if available
   386→    const categoryEnhancement = extractedFeatures.categoryEnhancements?.[category];
   387→    if (categoryEnhancement) {
   388→      confidenceBoost = categoryEnhancement.confidenceBoost || 0;
   389→
   390→      // Apply positive boosts only when category applies, but apply negative boosts regardless
   391→      if (categoryEnhancement.applies || confidenceBoost < 0) {
   392→        enhancedScore = originalScore + originalScore * confidenceBoost;
   393→        boostReason = `Applied ${confidenceBoost > 0 ? 'positive' : 'negative'} confidence boost based on AI features`;
   394→      }
   395→    }
   396→
   397→    enhancedScores[category] = enhancedScore;
   398→
   399→    // Track enhancement calculation for explainability
   400→    enhancementCalculations.push({
   401→      category,
   402→      originalScore,
   403→      confidenceBoost,
   404→      enhancedScore,
   405→      boostReason,
   406→    });
   407→  }
   408→
   409→  return enhancedScores;
   410→}
   411→
   412→/**
   413→ * Evaluate skip conditions to determine if AI classification should be bypassed
   414→ */
   415→function evaluateSkipConditions(
   416→  enhancedScores: Record<string, number>,
   417→  extractedFeatures: FeatureExtractionData,
   418→  config: AIClassificationConfig
   419→): AIRoutingDecision {
   420→  const skipConditionsEvaluated: string[] = [];
   421→
   422→  // Find highest scoring category
   423→  const maxScore = Math.max(...Object.values(enhancedScores));
   424→
   425→  // Check for hard assertion condition first (highest priority)
   426→  if (config.skipConditions.skipReasons.includes('hardAssertion')) {
   427→    skipConditionsEvaluated.push('hardAssertion');
   428→    if ((extractedFeatures as unknown as Record<string, unknown>).hardAssertionDetected) {
   429→      return {
   430→        routedToAI: false,
   431→        reason: 'hardAssertion',
   432→        skipConditionsEvaluated,
   433→        decisionRationale: 'Hard assertion detected in earlier pipeline stage',
   434→      };
   435→    }
   436→  }
   437→
   438→  // Check high confidence threshold
   439→  skipConditionsEvaluated.push('highConfidenceThreshold');
   440→  if (maxScore >= config.skipConditions.highConfidenceThreshold) {
   441→    return {
   442→      routedToAI: false,
   443→      reason: 'highConfidence',
   444→      confidenceScore: maxScore,
   445→      threshold: config.skipConditions.highConfidenceThreshold,
   446→      skipConditionsEvaluated,
   447→      decisionRationale: `Highest category score (${maxScore}) exceeds high confidence threshold (${config.skipConditions.highConfidenceThreshold})`,
   448→    };
   449→  }
   450→
   451→  // Default: route to AI
   452→  return {
   453→    routedToAI: true,
   454→    reason: 'requiresAiClassification',
   455→    skipConditionsEvaluated,
   456→    decisionRationale: `Confidence scores require AI classification (max: ${maxScore}, threshold: ${config.skipConditions.highConfidenceThreshold})`,
   457→  };
   458→}
   459→
   460→/**
   461→ * Create direct classification result when AI is skipped
   462→ */
   463→function createDirectClassification(enhancedScores: Record<string, number>, skipReason: string): FinalClassification {
   464→  // Sort categories by score descending
   465→  const sortedCategories = Object.entries(enhancedScores)
   466→    .sort(([, a], [, b]) => b - a)
   467→    .filter(([, score]) => score > 0);
   468→
   469→  if (sortedCategories.length === 0) {
   470→    return {
   471→      primaryCategory: 'unclassified',
   472→      secondaryCategories: [],
   473→      confidence: 0.5,
   474→      reasoning: `No categories scored above 0. Skip reason: ${skipReason}`,
   475→      categoryScores: enhancedScores,
   476→    };
   477→  }
   478→
   479→  const primaryCategory = sortedCategories[0][0];
   480→  const primaryScore = sortedCategories[0][1];
   481→
   482→  // Determine secondary categories (score > 3 and not primary)
   483→  const secondaryCategories = sortedCategories
   484→    .slice(1)
   485→    .filter(([, score]) => score > 3)
   486→    .map(([category]) => category);
   487→
   488→  // Calculate confidence based on score magnitude and separation
   489→  const confidence = Math.min(0.95, Math.max(0.5, primaryScore / 20));
   490→
   491→  return {
   492→    primaryCategory: primaryCategory,
   493→    secondaryCategories: secondaryCategories,
   494→    confidence,
   495→    reasoning: `Direct classification: ${skipReason}. Primary category "${primaryCategory}" scored ${primaryScore.toFixed(2)}`,
   496→    categoryScores: enhancedScores,
   497→  };
   498→}
   499→
   500→/**
   501→ * Interpolate classification prompt template with enhanced scores and extracted features
   502→ *
   503→ * Reuses template interpolation utilities from ai-feature-extraction.ts
   504→ */
   505→function interpolateClassificationPrompt(
   506→  userPromptTemplate: string[],
   507→  email: EmailMessage,
   508→  enhancedScores: Record<string, number>,
   509→  extractedFeatures: FeatureExtractionData
   510→): string {
   511→  const template = userPromptTemplate.join('\n');
   512→
   513→  // Create interpolation context with all available data
   514→  const context = {
   515→    email: {
   516→      from: formatEmailAddress(email.from),
   517→      subject: email.subject || '',
   518→      body: getEmailBodyText(email),
   519→    },
   520→    candidateCategories: formatObjectForTemplate(enhancedScores),
   521→    extractedFeatures: formatObjectForTemplate(extractedFeatures as unknown as Record<string, unknown>),
   522→  };
   523→
   524→  // Perform template interpolation using dynamic path resolution
   525→  return interpolateTemplate(template, context);
   526→}
   527→
   528→/**
   529→ * Validate AI response structure matches expected schema
   530→ */
   531→function validateAIResponse(response: Record<string, unknown>): void {
   532→  if (!response || typeof response !== 'object') {
   533→    throw new Error('AI response must be an object');
   534→  }
   535→
   536→  if (!response.primaryCategory || typeof response.primaryCategory !== 'string') {
   537→    throw new Error('AI response must include primaryCategory as string');
   538→  }
   539→
   540→  if (
   541→    response.confidence !== undefined &&
   542→    (typeof response.confidence !== 'number' || response.confidence < 0 || response.confidence > 1)
   543→  ) {
   544→    throw new Error('AI response confidence must be a number between 0 and 1');
   545→  }
   546→
   547→  if (response.secondaryCategories !== undefined && !Array.isArray(response.secondaryCategories)) {
   548→    throw new Error('AI response secondaryCategories must be an array');
   549→  }
   550→}
