        const reverseCombination = `${category}+${primaryCategory}`;

        // Check if this specific combination is allowed
        const isAllowed =
          rules.allowedCombinations.includes(combination) || rules.allowedCombinations.includes(reverseCombination);

        if (!isAllowed) {
          filteredLabels.push({
            category,
            filterReason: `Combination ${combination} not in allowed list`,
          });
          processingSteps.push(`Filtered ${category}: combination with ${primaryCategory} not allowed`);
        }

        return isAllowed;
      });
    }

